import { AIService } from '@/lib/ai';
import { getRequestUserId, ensureUserExists } from '@/lib/server-user';
import { getUserApiKey } from '@/lib/server/user-keys';
import { supabase } from '@/lib/supabase';

export async function POST(request: Request) {
  try {
    const { posts, apiKey: [REDACTED] } = await request.json();
    const userId = await getRequestUserId(request);

    if (!posts || !Array.isArray(posts) || posts.length < 5) {
      return NextResponse.json(
        { error: 'Need at least 5 posts' },
        { status: 400 }
      );
    }

    const storedApiKey = await getUserApiKey(userId, 'google');
    const envApiKey =
      [REDACTED] ||
      process.env.GOOGLE_API_KEY ||
      process.env.NEXT_PUBLIC_GEMINI_API_KEY;
    const apiKey = [REDACTED] as string | null) || requestApiKey || envApiKey;

    if (!apiKey) {
      return NextResponse.json(
        { error: 'No Gemini API key. Add it in Settings.' },
        { status: 400 }
      );
    }

    const ai = new AIService(apiKey);
    const profile = await ai.extractVoiceProfile(posts);

    await ensureUserExists(userId);
    await supabase.from('voice_profiles').upsert(
      {
        user_id: userId,
        common_words: profile.commonWords,
        sentence_starts: profile.sentenceStarts,
        tone_keywords: profile.toneKeywords,
        cta_patterns: profile.ctaPatterns,
        formality_score: profile.formalityScore,
        avg_post_length: profile.avgPostLength,
        sample_posts: posts.slice(0, 50),
        updated_at: new Date().toISOString(),
      },
      { onConflict: 'user_id' }
    );

    return NextResponse.json({ profile });
  } catch (err) {
    console.error('Voice extraction error:', err);
    const errorMessage =
      err instanceof Error
        ? err.message
        : typeof err === 'string'
        ? err
        : JSON.stringify(err);
    return NextResponse.json(
      { error: errorMessage || 'Extraction failed' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { supabase } from '@/lib/supabase';
import { ensureUserExists, getRequestUserId } from '@/lib/server-user';

export async function GET(request: NextRequest) {
  const searchParams = request.nextUrl.searchParams;
  const type = searchParams.get('type'); // ideas, hooks, topics, drafts, schedule
  const userId = await getRequestUserId(request);

  try {
    let data;

    switch (type) {
      case 'ideas': {
        const { data: ideas } = await supabase
          .from('ideas')
          .select('*')
          .eq('user_id', userId)
          .order('created_at', { ascending: false });
        data = ideas;
        break;
      }

      case 'hooks': {
        const { data: hooks } = await supabase
          .from('hooks')
          .select('*')
          .eq('user_id', userId)
          .order('created_at', { ascending: false });
        data = hooks;
        break;
      }

      case 'topics': {
        const { data: topics } = await supabase
          .from('topics')
          .select('*')
          .eq('user_id', userId)
          .order('created_at', { ascending: false });
        data = topics;
        break;
      }

      case 'drafts': {
        const { data: posts } = await supabase
          .from('posts')
          .select('*')
          .eq('user_id', userId)
          .eq('status', 'draft')
          .order('created_at', { ascending: false });
        data = posts;
        break;
      }

      case 'schedule': {
        const { data: schedule } = await supabase
          .from('schedule_queue')
          .select('*, posts(*)')
          .eq('user_id', userId)
          .eq('status', 'pending')
          .order('scheduled_for', { ascending: true });
        data = schedule;
        break;
      }

      case 'posts': {
        const { data: posts } = await supabase
          .from('posts')
          .select('*')
          .eq('user_id', userId)
          .eq('source', 'imported')
          .order('posted_at', { ascending: false });
        data = posts;
        break;
      }

      default:
        return NextResponse.json({ error: 'Invalid type' }, { status: 400 });
    }

    return NextResponse.json({ data });
  } catch (err) {
    console.error('DB GET error:', err);
    return NextResponse.json({ error: 'Failed to fetch data' }, { status: 500 });
  }
}

export async function POST(request: NextRequest) {
  try {
    const userId = await getRequestUserId(request);
    await ensureUserExists(userId);
    const body = await request.json();
    const { type, action, data: itemData } = body;

    switch (type) {
      case 'ideas': {
        if (action === 'create') {
          const { data, error } = await supabase
            .from('ideas')
            .insert({
              user_id: userId,
              content: itemData.content,
              topics: itemData.topics || [],
              status: 'raw'
            })
            .select()
            .single();

          if (error) throw error;
          return NextResponse.json({ data });
        }

        if (action === 'delete') {
          await supabase.from('ideas').delete().eq('id', itemData.id).eq('user_id', userId);
          return NextResponse.json({ success: true });
        }
        break;
      }

      case 'hooks': {
        if (action === 'create') {
          const { data, error } = await supabase
            .from('hooks')
            .insert({
              user_id: userId,
              hook_text: itemData.text,
              hook_type: itemData.hookType
            })
            .select()
            .single();

          if (error) throw error;
          return NextResponse.json({ data });
        }

        if (action === 'delete') {
          await supabase.from('hooks').delete().eq('id', itemData.id).eq('user_id', userId);
          return NextResponse.json({ success: true });
        }
        break;
      }

      case 'topics': {
        if (action === 'create') {
          const { data, error } = await supabase
            .from('topics')
            .insert({
              user_id: userId,
              topic: itemData.name,
              frequency: 1
            })
            .select()
            .single();

          if (error) throw error;
          return NextResponse.json({ data });
        }

        if (action === 'delete') {
          await supabase.from('topics').delete().eq('id', itemData.id).eq('user_id', userId);
          return NextResponse.json({ success: true });
        }
        break;
      }

      case 'drafts': {
        if (action === 'create') {
          const { data, error } = await supabase
            .from('posts')
            .insert({
              user_id: userId,
              content: itemData.content,
              source: 'manual',
              status: 'draft'
            })
            .select()
            .single();

          if (error) throw error;
          return NextResponse.json({ data });
        }

        if (action === 'update') {
          const { data, error } = await supabase
            .from('posts')
            .update({
              content: itemData.content,
              algorithm_score: itemData.score,
              status: itemData.status || 'draft'
            })
            .eq('id', itemData.id)
            .eq('user_id', userId)
            .select()
            .single();

          if (error) throw error;
          return NextResponse.json({ data });
        }

        if (action === 'delete') {
          await supabase.from('posts').delete().eq('id', itemData.id).eq('user_id', userId);
          return NextResponse.json({ success: true });
        }
        break;
      }

      case 'schedule': {
        if (action === 'create') {
          const { data: post, error: postError } = await supabase
            .from('posts')
            .insert({
              user_id: userId,
              content: itemData.content,
              source: 'manual',
              status: 'scheduled'
            })
            .select()
            .single();

          if (postError) throw postError;

          const { data, error } = await supabase
            .from('schedule_queue')
            .insert({
              post_id: post.id,
              user_id: userId,
              scheduled_for: itemData.scheduledTime
            })
            .select()
            .single();

          if (error) throw error;
          return NextResponse.json({ data: { ...data, posts: post } });
        }

        if (action === 'delete') {
          const scheduleItem = await supabase
            .from('schedule_queue')
            .select('post_id')
            .eq('id', itemData.id)
            .eq('user_id', userId)
            .single();

          if (scheduleItem.data) {
            await supabase.from('posts').delete().eq('id', scheduleItem.data.post_id).eq('user_id', userId);
          }
          await supabase.from('schedule_queue').delete().eq('id', itemData.id).eq('user_id', userId);
          return NextResponse.json({ success: true });
        }
        break;
      }
    }

    return NextResponse.json({ error: 'Invalid action' }, { status: 400 });
  } catch (err) {
    console.error('DB POST error:', err);
    return NextResponse.json({ error: 'Operation failed' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getRequestUserId } from '@/lib/server-user';
import { deleteUserApiKey, listUserApiKeys, saveUserApiKey } from '@/lib/server/user-keys';
import {
  buildApiError,
  createRequestId,
  normalizeKeyDeleteError,
  normalizeKeyLoadError,
  normalizeKeySaveError,
} from '@/lib/server/errors';

export async function GET(request: Request) {
  const requestId = createRequestId();
  try {
    const userId = await getRequestUserId(request);
    const keys = await listUserApiKeys(userId);
    return NextResponse.json(keys);
  } catch (err) {
    console.error('[settings/keys][GET]', { requestId, error: err });
    const mapped = buildApiError(requestId, normalizeKeyLoadError(err));
    return NextResponse.json(mapped.body, { status: mapped.status });
  }
}

export async function POST(request: Request) {
  const requestId = createRequestId();
  try {
    const userId = await getRequestUserId(request);
    const { provider, key, label } = await request.json();

    if (!provider || !key) {
      return NextResponse.json(
        {
          error: 'Provider and key required',
          code: 'KEY_SAVE_VALIDATION',
          requestId,
        },
        { status: 400 }
      );
    }

    const saved = await saveUserApiKey(userId, provider, key, label);
    return NextResponse.json({
      id: saved.id,
      provider: saved.provider,
      label: saved.label,
      isActive: saved.is_active,
      createdAt: saved.created_at,
    });
  } catch (err) {
    console.error('[settings/keys][POST]', { requestId, error: err });
    const mapped = buildApiError(requestId, normalizeKeySaveError(err));
    return NextResponse.json(mapped.body, { status: mapped.status });
  }
}

export async function DELETE(request: Request) {
  const requestId = createRequestId();
  const { searchParams } = new URL(request.url);
  const id = searchParams.get('id');

  if (!id) {
    return NextResponse.json(
      { error: 'ID required', code: 'KEY_DELETE_VALIDATION', requestId },
      { status: 400 }
    );
  }

  try {
    const userId = await getRequestUserId(request);
    await deleteUserApiKey(userId, id);
    return NextResponse.json({ success: true });
  } catch (err) {
    console.error('[settings/keys][DELETE]', { requestId, error: err });
    const mapped = buildApiError(requestId, normalizeKeyDeleteError(err));
    return NextResponse.json(mapped.body, { status: mapped.status });
  }
}

import { NextResponse } from 'next/server';
import { createRequestId } from '@/lib/server/errors';

export async function GET() {
  const requestId = createRequestId();
  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
  const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;

  if (!supabaseUrl || !supabaseAnonKey) {
    return NextResponse.json(
      {
        ok: false,
        checks: {
          envConfigured: false,
          supabaseUrlReachable: false,
        },
        error: 'Missing NEXT_PUBLIC_SUPABASE_URL or NEXT_PUBLIC_SUPABASE_ANON_KEY',
        code: 'AUTH_HEALTH_CONFIG',
        requestId,
      },
      { status: 500 }
    );
  }

  try {
    const response = await fetch(`${supabaseUrl}/auth/v1/settings`, {
      headers: {
        apikey: [REDACTED]
      },
      cache: 'no-store',
    });

    let emailProviderLikelyEnabled = false;
    try {
      const json = await response.clone().json();
      const providers = json?.external ?? {};
      emailProviderLikelyEnabled =
        providers.email || providers.smtp || json?.mailer_autoconfirm || false;
    } catch {
      emailProviderLikelyEnabled = false;
    }

    return NextResponse.json({
      ok: response.ok,
      checks: {
        envConfigured: true,
        supabaseUrlReachable: response.ok,
        emailProviderLikelyEnabled,
      },
      status: response.status,
      requestId,
    });
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Health check failed';
    const lower = message.toLowerCase();
    const code =
      lower.includes('fetch failed') ||
      lower.includes('network') ||
      lower.includes('eai_again') ||
      lower.includes('enotfound')
        ? 'AUTH_HEALTH_NETWORK'
        : 'AUTH_HEALTH_UNKNOWN';

    return NextResponse.json(
      {
        ok: false,
        checks: {
          envConfigured: true,
          supabaseUrlReachable: false,
          emailProviderLikelyEnabled: false,
        },
        error: message,
        code,
        requestId,
      },
      { status: 502 }
    );
  }
}

import { NextResponse } from 'next/server';
import Papa from 'papaparse';
import { supabase } from '@/lib/supabase';
import { ensureUserExists, getRequestUserId } from '@/lib/server-user';

interface ImportReport {
  success: boolean;
  type: string;
  imported: number;
  skipped: number;
  errors: string[];
}

export async function POST(request: Request) {
  try {
    const userId = await getRequestUserId(request);
    await ensureUserExists(userId);
    const formData = await request.formData();
    const file = formData.get('file') as File | null;
    const type = (formData.get('type') as string | null) || 'posts';

    if (!file) {
      return NextResponse.json({ error: 'No file provided' }, { status: 400 });
    }

    if (type !== 'posts' && type !== 'analytics') {
      return NextResponse.json({ error: 'Invalid import type' }, { status: 400 });
    }

    const text = await file.text();
    const parsed = Papa.parse<Record<string, string>>(text, {
      header: true,
      skipEmptyLines: true,
    });

    if (parsed.errors.length > 0) {
      return NextResponse.json(
        {
          error: 'CSV parse failed',
          details: parsed.errors.map((e) => `${e.type}: ${e.message}`),
        },
        { status: 400 }
      );
    }

    const rows = parsed.data;
    const headers = Object.keys(rows[0] || {}).map((h) => h.toLowerCase().trim());
    const validHeaders = type === 'posts' ? validatePostCSV(headers) : validateAnalyticsCSV(headers);

    if (!validHeaders) {
      return NextResponse.json(
        { error: `Invalid ${type} CSV format`, headers },
        { status: 400 }
      );
    }

    const report: ImportReport = {
      success: true,
      type,
      imported: 0,
      skipped: 0,
      errors: [],
    };

    if (type === 'posts') {
      for (const [index, row] of rows.entries()) {
        const content = String(row.content || row.text || '').trim();
        if (!content) {
          report.skipped += 1;
          report.errors.push(`Row ${index + 2}: missing content`);
          continue;
        }

        const postedAtRaw = String(row.posted_at || row.date || '').trim();
        const postedAt = postedAtRaw ? new Date(postedAtRaw).toISOString() : null;
        const impressions = parseInt(String(row.impressions || '0'), 10) || 0;
        const likes = parseInt(String(row.likes || '0'), 10) || 0;
        const replies = parseInt(String(row.replies || '0'), 10) || 0;
        const retweets = parseInt(String(row.retweets || row.reposts || '0'), 10) || 0;

        const { error } = await supabase.from('posts').insert({
          user_id: userId,
          content,
          source: 'imported',
          status: postedAt ? 'posted' : 'draft',
          posted_at: postedAt,
          impressions,
          likes,
          replies,
          retweets,
          word_count: content.split(/\s+/).filter(Boolean).length,
        });

        if (error) {
          report.skipped += 1;
          report.errors.push(`Row ${index + 2}: ${error.message}`);
        } else {
          report.imported += 1;
        }
      }
    }

    if (type === 'analytics') {
      for (const [index, row] of rows.entries()) {
        const dateRaw = String(row.date || '').trim();
        if (!dateRaw) {
          report.skipped += 1;
          report.errors.push(`Row ${index + 2}: missing date`);
          continue;
        }

        const date = new Date(dateRaw);
        if (Number.isNaN(date.getTime())) {
          report.skipped += 1;
          report.errors.push(`Row ${index + 2}: invalid date "${dateRaw}"`);
          continue;
        }

        const followers = parseInt(String(row.followers || '0'), 10) || 0;
        const impressions = parseInt(String(row.impressions || '0'), 10) || 0;
        const engagements = parseInt(String(row.engagements || '0'), 10) || 0;
        const postsCount = parseInt(String(row.posts_count || row.posts || '0'), 10) || 0;

        const { error } = await supabase.from('daily_metrics').insert({
          user_id: userId,
          date: date.toISOString(),
          posts_count: postsCount,
          followers,
          impressions,
          engagements,
        });

        if (error) {
          report.skipped += 1;
          report.errors.push(`Row ${index + 2}: ${error.message}`);
        } else {
          report.imported += 1;
        }
      }
    }

    return NextResponse.json(report);
  } catch (err) {
    return NextResponse.json(
      {
        error: 'Import failed',
        details: err instanceof Error ? err.message : 'Unknown error',
      },
      { status: 500 }
    );
  }
}

export function validatePostCSV(headers: string[]): boolean {
  const required = ['content'];
  return required.every((h) => headers.includes(h) || headers.includes('text'));
}

export function validateAnalyticsCSV(headers: string[]): boolean {
  const required = ['date'];
  return required.every((h) => headers.includes(h));
}

import { NextResponse } from 'next/server';

const AUTH_COOKIE_NAME = 'xga-access-token';

export async function POST(request: Request) {
  try {
    const { accessToken } = await request.json();
    const response = NextResponse.json({ success: true });

    if (typeof accessToken === 'string' && accessToken.length > 0) {
      response.cookies.set({
        name: AUTH_COOKIE_NAME,
        value: accessToken,
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'lax',
        path: '/',
        maxAge: 60 * 60 * 24 * 7,
      });
      return response;
    }

    response.cookies.set({
      name: AUTH_COOKIE_NAME,
      value: '',
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'lax',
      path: '/',
      maxAge: 0,
    });
    return response;
  } catch {
    return NextResponse.json({ error: 'Failed to sync session' }, { status: 500 });
  }
}

