import toast from "react-hot-toast";
import { Tag, Plus, X, ArrowLeft } from "lucide-react";
import Link from "next/link";

interface Topic {
  id: string;
  topic: string;
  color?: string;
  created_at: string;
}

const PALETTE = [
  "#6366f1", "#8b5cf6", "#ec4899", "#ef4444",
  "#f59e0b", "#10b981", "#06b6d4", "#84cc16",
  "#f97316", "#a78bfa",
