const FORMATS = [
  {
    id: "short",
    label: "Short version",
    description: "Compressed to the core insight",
    icon: AlignLeft,
    color: "indigo",
  },
  {
    id: "thread",
    label: "Thread",
    description: "Expanded into a multi-tweet thread",
    icon: List,
    color: "purple",
  },
  {
    id: "quote",
    label: "Quote tweet",
    description: "Framed as a quotable one-liner",
    icon: Quote,
