  },
  {
    id: "reply",
    label: "Reply bait",
    description: "Rewritten to invite discussion",
    icon: MessageSquare,
    color: "success",
  },
  {
    id: "newsletter",
    label: "Newsletter intro",
    description: "Expanded for email newsletter",
    icon: Mail,
