import { useEffect, useState } from 'react';
import { Save, RotateCcw } from 'lucide-react';
import toast from 'react-hot-toast';
import type { RadarSettings } from '@/lib/radar/types';

const DEFAULT_WEIGHTS = {
  niche_relevance: 0.24,
  novelty: 0.18,
  momentum: 0.16,
  earlyness: 0.14,
  source_quality: 0.10,
  audience_fit: 0.08,
  actionability: 0.06,
