export default function RadarSettingsPage() {
  const [settings, setSettings] = useState<RadarSettings | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [keywordsText, setKeywordsText] = useState('');

  useEffect(() => {
    fetch('/api/radar/settings')
      .then((r) => r.json())
      .then((d: { settings: RadarSettings }) => {
        setSettings(d.settings);
        setKeywordsText((d.settings.nicheKeywords ?? []).join(', '));
        setLoading(false);
      });
  }, []);

  async function saveSettings() {
    if (!settings) return;
    setSaving(true);
    const payload = {
      ...settings,
      nicheKeywords: keywordsText.split(',').map((k) => k.trim()).filter(Boolean),
    };
    const res = await fetch('/api/radar/settings', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload),
    });
    if (res.ok) {
      toast.success('Settings saved');
    } else {
      toast.error('Failed to save');
    }
    setSaving(false);
  }

  function updateWeight(key: string, value: number) {
    if (!settings) return;
    setSettings((prev) => prev ? ({
      ...prev,
      scoreWeights: { ...prev.scoreWeights, [key]: value },
    }) : prev);
  }

  function updateThreshold(key: string, value: number) {
    if (!settings) return;
    setSettings((prev) => prev ? ({
      ...prev,
      scoreThresholds: { ...prev.scoreThresholds, [key]: value },
    }) : prev);
  }

  if (loading) {
    return (
      <div className="space-y-4">
        {[...Array(4)].map((_, i) => <div key={i} className="h-32 rounded-xl bg-[#1c1c2e] animate-pulse" />)}
      </div>
    );
  }

  if (!settings) return null;

  const weightTotal = Object.values(settings.scoreWeights).reduce((a, b) => a + b, 0);

  return (
    <div className="space-y-6 max-w-2xl">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-xl font-bold text-[#f1f5f9]">Radar Settings</h1>
          <p className="text-[13px] text-[#94a3b8] mt-0.5">Tune scoring thresholds, weights, and behaviour</p>
        </div>
        <button
          onClick={saveSettings}
          disabled={saving}
          className="flex items-center gap-2 px-4 py-2 rounded-xl bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 text-white text-sm font-medium transition-colors"
        >
          <Save size={14} />
          {saving ? 'Saving…' : 'Save Changes'}
        </button>
      </div>

      {/* Score thresholds */}
      <SettingCard title="Score Thresholds" description="When clusters change state based on score">
        <div className="grid grid-cols-3 gap-4">
          {Object.entries(settings.scoreThresholds).map(([key, val]) => (
            <div key={key}>
              <label className="block text-[11px] text-[#94a3b8] mb-1 capitalize">{key} (score ≥)</label>
              <input
                type="number"
                min={0}
                max={100}
                value={val}
                onChange={(e) => updateThreshold(key, parseInt(e.target.value))}
                className="w-full px-3 py-2 rounded-lg bg-[#161625] border border-[#2a2a45] text-[#f1f5f9] text-sm focus:outline-none focus:border-indigo-500"
              />
            </div>
          ))}
        </div>
      </SettingCard>

      {/* Alert cooldown */}
      <SettingCard title="Alert Behaviour" description="Anti-spam rules for Discord notifications">
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[11px] text-[#94a3b8] mb-1">Cooldown (hours)</label>
            <input
              type="number"
              min={1}
              max={72}
              value={settings.alertCooldownHours}
              onChange={(e) => setSettings((p) => p ? ({ ...p, alertCooldownHours: parseInt(e.target.value) }) : p)}
              className="w-full px-3 py-2 rounded-lg bg-[#161625] border border-[#2a2a45] text-[#f1f5f9] text-sm focus:outline-none focus:border-indigo-500"
            />
            <p className="text-[10px] text-[#4b5563] mt-1">Min hours between alerts for same cluster</p>
          </div>
          <div>
            <label className="block text-[11px] text-[#94a3b8] mb-1">Score jump override</label>
            <input
              type="number"
              min={5}
              max={50}
              value={settings.scoreJumpOverride}
              onChange={(e) => setSettings((p) => p ? ({ ...p, scoreJumpOverride: parseInt(e.target.value) }) : p)}
              className="w-full px-3 py-2 rounded-lg bg-[#161625] border border-[#2a2a45] text-[#f1f5f9] text-sm focus:outline-none focus:border-indigo-500"
            />
            <p className="text-[10px] text-[#4b5563] mt-1">Override cooldown if score jumps by this much</p>
          </div>
        </div>
      </SettingCard>

      {/* Cluster lifecycle */}
      <SettingCard title="Cluster Lifecycle" description="How long to keep stale clusters">
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-[11px] text-[#94a3b8] mb-1">Max cluster age (days)</label>
            <input
              type="number"
              min={1}
              max={30}
              value={settings.maxClusterAgeDays}
              onChange={(e) => setSettings((p) => p ? ({ ...p, maxClusterAgeDays: parseInt(e.target.value) }) : p)}
              className="w-full px-3 py-2 rounded-lg bg-[#161625] border border-[#2a2a45] text-[#f1f5f9] text-sm focus:outline-none focus:border-indigo-500"
            />
            <p className="text-[10px] text-[#4b5563] mt-1">Auto-archive clusters older than this</p>
          </div>
          <div>
            <label className="block text-[11px] text-[#94a3b8] mb-1">Fetch interval (minutes)</label>
            <input
              type="number"
              min={5}
              max={60}
              value={settings.ingestionIntervalMin}
              onChange={(e) => setSettings((p) => p ? ({ ...p, ingestionIntervalMin: parseInt(e.target.value) }) : p)}
              className="w-full px-3 py-2 rounded-lg bg-[#161625] border border-[#2a2a45] text-[#f1f5f9] text-sm focus:outline-none focus:border-indigo-500"
            />
            <p className="text-[10px] text-[#4b5563] mt-1">How often the cron job runs</p>
          </div>
        </div>
      </SettingCard>

      {/* Niche keywords */}
      <SettingCard title="Niche Keywords" description="Boost niche_relevance score when these appear in content">
        <textarea
          value={keywordsText}
          onChange={(e) => setKeywordsText(e.target.value)}
          rows={3}
          placeholder="AI, SEO, search, content, creator, WordPress, Google"
          className="w-full px-3 py-2 rounded-lg bg-[#161625] border border-[#2a2a45] text-[#f1f5f9] text-sm focus:outline-none focus:border-indigo-500 resize-none"
        />
        <p className="text-[10px] text-[#4b5563] mt-1">Comma-separated. Case-insensitive.</p>
      </SettingCard>

      {/* Score weights */}
      <SettingCard
        title="Score Weights"
        description={`Dimension weights (must sum to 1.0 — current: ${weightTotal.toFixed(2)})`}
        warning={Math.abs(weightTotal - 1.0) > 0.01 ? `Warning: weights sum to ${weightTotal.toFixed(2)}, not 1.0` : undefined}
      >
        <div className="space-y-3">
          {Object.entries(settings.scoreWeights).map(([key, val]) => (
            <div key={key} className="flex items-center gap-3">
              <label className="text-[12px] text-[#94a3b8] w-36 shrink-0 capitalize">{key.replace(/_/g, ' ')}</label>
              <input
                type="range"
                min={0}
                max={0.5}
                step={0.01}
                value={val}
                onChange={(e) => updateWeight(key, parseFloat(e.target.value))}
                className="flex-1 accent-indigo-500"
              />
              <span className="text-[12px] font-medium text-[#f1f5f9] w-10 text-right">{val.toFixed(2)}</span>
            </div>
          ))}
        </div>
        <button
          onClick={() => setSettings((p) => p ? ({ ...p, scoreWeights: DEFAULT_WEIGHTS }) : p)}
          className="mt-3 flex items-center gap-1.5 text-[11px] text-[#4b5563] hover:text-[#94a3b8] transition-colors"
        >
          <RotateCcw size={11} /> Reset to defaults
        </button>
      </SettingCard>
    </div>
  );
}

function SettingCard({
  title,
  description,
  children,
  warning,
}: {
  title: string;
  description: string;
  children: React.ReactNode;
  warning?: string;
}) {
  return (
    <div className="p-5 rounded-xl bg-[#0f0f1a] border border-[#1e1e35]">
      <h2 className="text-[13px] font-semibold text-[#f1f5f9] mb-0.5">{title}</h2>
      <p className="text-[11px] text-[#4b5563] mb-4">{description}</p>
      {warning && (
        <p className="text-[11px] text-amber-400 mb-3 p-2 rounded-lg bg-amber-500/10 border border-amber-500/20">{warning}</p>
      )}
      {children}
    </div>
  );
}

"use client";

import { useEffect, useState } from 'react';
import { CheckCircle, AlertTriangle, XCircle, Globe, ExternalLink } from 'lucide-react';
import toast from 'react-hot-toast';

interface Source {
  id: string;
  name: string;
  category: string;
  type: string;
  homepage_url: string;
  feed_url: string | null;
  enabled: boolean;
  trust_score: number;
  speed_score: number;
  noise_score: number;
  notes: string | null;
  last_checked_at: string | null;
  health_status: string;
  consecutive_failures: number;
}

const HEALTH_ICONS: Record<string, React.ReactNode> = {
  healthy: <CheckCircle size={12} className="text-emerald-400" />,
  degraded: <AlertTriangle size={12} className="text-amber-400" />,
  failing: <XCircle size={12} className="text-red-400" />,
  unknown: <Globe size={12} className="text-[#4b5563]" />,
};

const CATEGORY_COLORS: Record<string, string> = {
  'AI': 'text-purple-400',
  'Search': 'text-blue-400',
  'SEO': 'text-indigo-400',
  'Social': 'text-pink-400',
  'WordPress': 'text-cyan-400',
  'Publishing': 'text-amber-400',
  'Creator Economy': 'text-orange-400',
  'Big Tech': 'text-red-400',
  'Tools': 'text-emerald-400',
};

function timeAgo(date: string): string {
  const diff = Date.now() - new Date(date).getTime();
  const h = Math.floor(diff / 3_600_000);
  const m = Math.floor(diff / 60_000);
  if (h >= 24) return `${Math.floor(h / 24)}d ago`;
  if (h >= 1) return `${h}h ago`;
  return `${m}m ago`;
}

function ScoreCell({ label, value }: { label: string; value: number }) {
  const color = value >= 8 ? 'text-emerald-400' : value >= 5 ? 'text-amber-400' : 'text-red-400';
  return (
    <div className="text-center">
      <span className={`text-[11px] font-bold ${color}`}>{value}</span>
      <p className="text-[9px] text-[#4b5563] mt-0.5">{label}</p>
    </div>
  );
}

export default function SourcesPage() {
  const [sources, setSources] = useState<Source[]>([]);
  const [loading, setLoading] = useState(true);
  const [categoryFilter, setCategoryFilter] = useState('all');

  async function fetchSources() {
    setLoading(true);
    const res = await fetch('/api/radar/sources');
    const data = await res.json() as { data?: Source[] };
    setSources(data.data ?? []);
    setLoading(false);
  }

  useEffect(() => { fetchSources(); }, []);

  async function toggleSource(source: Source) {
    const res = await fetch('/api/radar/sources', {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id: source.id, enabled: !source.enabled }),
    });
    if (res.ok) {
      setSources((prev) => prev.map((s) => s.id === source.id ? { ...s, enabled: !s.enabled } : s));
      toast.success(source.enabled ? `Disabled ${source.name}` : `Enabled ${source.name}`);
    }
  }

  const categories = ['all', ...new Set(sources.map((s) => s.category))].sort();
  const filtered = categoryFilter === 'all' ? sources : sources.filter((s) => s.category === categoryFilter);

  const healthyCount = sources.filter((s) => s.health_status === 'healthy').length;
  const failingCount = sources.filter((s) => s.health_status === 'failing').length;
  const enabledCount = sources.filter((s) => s.enabled).length;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-4">
        <div>
          <h1 className="text-xl font-bold text-[#f1f5f9]">Sources</h1>
          <p className="text-[13px] text-[#94a3b8] mt-0.5">
            {enabledCount}/{sources.length} enabled · {healthyCount} healthy · {failingCount} failing
          </p>
        </div>
      </div>

      {/* Category filter */}
      <div className="flex flex-wrap gap-2">
        {categories.map((cat) => (
          <button
            key={cat}
            onClick={() => setCategoryFilter(cat)}
            className={`px-3 py-1 rounded-full text-[12px] font-medium transition-colors border ${
              categoryFilter === cat
                ? 'bg-indigo-600 text-white border-indigo-500'
                : 'bg-[#0f0f1a] text-[#94a3b8] border-[#2a2a45] hover:border-indigo-500/30'
            }`}
          >
            {cat}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="space-y-2">
          {[...Array(10)].map((_, i) => <div key={i} className="h-16 rounded-xl bg-[#1c1c2e] animate-pulse" />)}
        </div>
      ) : (
        <div className="space-y-1">
          {filtered.map((source) => (
            <div
              key={source.id}
              className={`flex items-center gap-4 px-4 py-3 rounded-xl border transition-all ${
                source.enabled
                  ? 'bg-[#0f0f1a] border-[#1e1e35]'
                  : 'bg-[#0a0a14] border-[#161625] opacity-60'
              }`}
            >
              {/* Health indicator */}
              <div className="shrink-0">{HEALTH_ICONS[source.health_status]}</div>

              {/* Name & category */}
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <a
                    href={source.homepage_url}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="text-[13px] font-medium text-[#f1f5f9] hover:text-indigo-300 flex items-center gap-1"
                  >
                    {source.name}
                    <ExternalLink size={10} className="opacity-50" />
                  </a>
                  <span className={`text-[10px] font-medium ${CATEGORY_COLORS[source.category] ?? 'text-[#94a3b8]'}`}>
                    {source.category}
                  </span>
                  <span className="text-[10px] text-[#2a2a45] border border-[#2a2a45] px-1.5 py-0.5 rounded">{source.type}</span>
                </div>
                {source.last_checked_at && (
                  <p className="text-[11px] text-[#4b5563] mt-0.5">
                    Last checked {timeAgo(source.last_checked_at)}
                    {source.consecutive_failures > 0 && (
                      <span className="text-red-400 ml-2">{source.consecutive_failures} failures</span>
                    )}
                  </p>
                )}
              </div>

              {/* Score cells */}
              <div className="hidden lg:flex items-center gap-4 shrink-0">
                <ScoreCell label="Trust" value={source.trust_score} />
                <ScoreCell label="Speed" value={source.speed_score} />
                <ScoreCell label="Noise" value={source.noise_score} />
              </div>

              {/* Toggle */}
              <button
                onClick={() => toggleSource(source)}
                className={`shrink-0 w-10 h-5 rounded-full transition-all relative ${
                  source.enabled ? 'bg-indigo-600' : 'bg-[#1c1c2e]'
                }`}
              >
                <span className={`absolute top-0.5 w-4 h-4 rounded-full bg-white transition-all ${
                  source.enabled ? 'left-5' : 'left-0.5'
                }`} />
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

"use client";

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { TrendingUp, TrendingDown, Minus } from 'lucide-react';

interface Cluster {
  id: string;
  canonical_headline: string;
  status: string;
  latest_score: number;
  source_count: number;
  source_diversity: number;
  tags: string[];
  first_seen_at: string;
  last_seen_at: string;
  why_flagged: string | null;
}

function timeAgo(date: string): string {
  const diff = Date.now() - new Date(date).getTime();
  const h = Math.floor(diff / 3_600_000);
  if (h >= 24) return `${Math.floor(h / 24)}d ago`;
  if (h >= 1) return `${h}h ago`;
  return `${Math.floor(diff / 60_000)}m ago`;
}

function MomentumIcon({ score }: { score: number }) {
  if (score >= 70) return <TrendingUp size={14} className="text-emerald-400" />;
  if (score >= 45) return <Minus size={14} className="text-amber-400" />;
  return <TrendingDown size={14} className="text-red-400" />;
}

export default function WatchlistPage() {
  const [clusters, setClusters] = useState<Cluster[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch('/api/radar/clusters?status=watchlist&limit=50')
      .then((r) => r.json())
      .then((d: { data?: Cluster[] }) => {
        setClusters((d.data ?? []).sort((a, b) => b.latest_score - a.latest_score));
        setLoading(false);
      });
  }, []);

  const movers = clusters.filter((c) => c.latest_score >= 60);
  const steady = clusters.filter((c) => c.latest_score >= 45 && c.latest_score < 60);
  const cooling = clusters.filter((c) => c.latest_score < 45);

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-xl font-bold text-[#f1f5f9]">Watchlist</h1>
        <p className="text-[13px] text-[#94a3b8] mt-0.5">
          {clusters.length} topics being monitored — {movers.length} approaching alert threshold
        </p>
      </div>

      {loading ? (
        <div className="space-y-2">
          {[...Array(8)].map((_, i) => <div key={i} className="h-20 rounded-xl bg-[#1c1c2e] animate-pulse" />)}
        </div>
      ) : clusters.length === 0 ? (
        <div className="text-center py-20 text-[#4b5563]">
          <p>No topics on the watchlist.</p>
          <p className="text-sm mt-1">Run the pipeline to start tracking topics.</p>
        </div>
      ) : (
        <>
          {movers.length > 0 && (
            <WatchlistSection title="Movers (score ≥ 60)" clusters={movers} highlight />
          )}
          {steady.length > 0 && (
            <WatchlistSection title="Steady (45–59)" clusters={steady} />
          )}
          {cooling.length > 0 && (
            <WatchlistSection title="Cooling (< 45)" clusters={cooling} />
          )}
        </>
      )}
    </div>
  );
}

function WatchlistSection({
  title,
  clusters,
  highlight = false,
}: {
  title: string;
  clusters: Cluster[];
  highlight?: boolean;
}) {
  return (
    <div>
      <h2 className={`text-[12px] font-semibold uppercase tracking-wide mb-3 ${highlight ? 'text-emerald-400' : 'text-[#4b5563]'}`}>
        {title}
      </h2>
      <div className="space-y-2">
        {clusters.map((cluster) => (
          <Link
            key={cluster.id}
            href={`/radar/clusters/${cluster.id}`}
            className={`flex items-center justify-between p-4 rounded-xl border transition-all hover:bg-[#161625] ${
              highlight
                ? 'bg-[#0f0f1a] border-emerald-500/20 hover:border-emerald-500/40'
                : 'bg-[#0f0f1a] border-[#1e1e35] hover:border-[#2a2a45]'
            }`}
          >
            <div className="flex items-center gap-3 min-w-0 flex-1">
              <MomentumIcon score={cluster.latest_score} />
              <div className="min-w-0 flex-1">
                <p className="text-[13px] font-medium text-[#f1f5f9] truncate">{cluster.canonical_headline}</p>
                <div className="flex items-center gap-2 mt-0.5">
                  <span className="text-[11px] text-[#4b5563]">{cluster.source_count} sources</span>
                  <span className="text-[#2a2a45]">·</span>
                  <span className="text-[11px] text-[#4b5563]">first {timeAgo(cluster.first_seen_at)}</span>
                  {cluster.tags?.slice(0, 2).map((tag) => (
                    <span key={tag} className="text-[10px] px-1.5 py-0.5 rounded bg-[#161625] text-[#4b5563] border border-[#2a2a45]">{tag}</span>
                  ))}
                </div>
              </div>
            </div>
            <div className="text-xl font-bold text-[#f1f5f9] ml-4 shrink-0">{cluster.latest_score}</div>
          </Link>
        ))}
      </div>
    </div>
  );
}

"use client";

import { useEffect, useState } from 'react';
import type { User } from '@supabase/supabase-js';
import { supabase } from '@/lib/supabase';

export function useAuthUser() {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadUser = async () => {
      const { data } = await supabase.auth.getUser();
      setUser(data.user ?? null);
      setLoading(false);
    };

    loadUser();

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
      setLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  return {
    user,
    loading,
    isAuthenticated: !!user,
  };
}
